/* BTToggleGroup styles — Figma 2864-12585.
   All colors via @btech/tokens CSS vars — no hex fallbacks. */

.bt-toggle-group {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--space-sm);
}

.bt-toggle-group--small {
  gap: var(--space-xs);
}

/**
 * BTToggleGroup — selection-state container for BTToggle items.
 * Figma source: node 2864-12585.
 * Owns selection state internally; exposes it via controlled `value` + `onChange`.
 * Forwards `variant`, `size`, and `disabled` to all child toggles.
 *
 * @example
 * ```tsx
 * // Single selection (default)
 * <BTToggleGroup items={items} value={selected} onChange={v => setSelected(v as string | null)} />
 *
 * // Multiple selection
 * <BTToggleGroup type="multiple" items={items} value={selectedArr} onChange={v => setSelectedArr(v as string[])} />
 *
 * // Outline variant, small size
 * <BTToggleGroup variant="outline" size="small" items={items} value={sel} onChange={v => setSel(v as string | null)} />
 * ```
 */
import { useState, useEffect } from 'react';
import './BTToggleGroup.css';
import { BTToggle } from '../toggle/BTToggle';
import type { BTToggleGroupProps, BTToggleGroupItem } from './BTToggleGroup.types';

export function BTToggleGroup<T = string>({
  items,
  type      = 'single',
  value,
  variant   = 'default',
  size      = 'default',
  disabled  = false,
  onChange,
  className,
}: BTToggleGroupProps<T>) {
  const [selected, setSelected] = useState<T | T[] | null>(() =>
    type === 'multiple'
      ? ((value as T[] | undefined) ?? [])
      : ((value as T | null | undefined) ?? null),
  );

  // Sync internal state when caller changes `value` externally.
  useEffect(() => {
    if (value !== undefined) setSelected(value ?? null);
  }, [value]);

  function isPressed(item: BTToggleGroupItem<T>): boolean {
    if (type === 'multiple') return (selected as T[]).includes(item.value);
    return selected === item.value;
  }

  function handleToggle(item: BTToggleGroupItem<T>) {
    if (disabled || item.disabled) return;
    let next: T | T[] | null;
    if (type === 'multiple') {
      const current = (selected as T[]) ?? [];
      next = current.includes(item.value)
        ? current.filter((v) => v !== item.value)
        : [...current, item.value];
    } else {
      next = selected === item.value ? null : item.value;
    }
    setSelected(next);
    onChange?.(next);
  }

  const cls = [
    'bt-toggle-group',
    size === 'small' ? 'bt-toggle-group--small' : '',
    className ?? '',
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div className={cls} role="group" data-testid="bt-toggle-group">
      {items.map((item) => (
        <BTToggle
          key={String(item.value)}
          label={item.label}
          pressed={isPressed(item)}
          variant={variant}
          size={size}
          disabled={disabled || !!item.disabled}
          onChange={() => handleToggle(item)}
        />
      ))}
    </div>
  );
}

BTToggleGroup.displayName = 'BTToggleGroup';

import type { BTToggleVariant, BTToggleSize } from '../toggle/BTToggle.types';

export type { BTToggleVariant, BTToggleSize };

export interface BTToggleGroupItem<T = string> {
  /** The value associated with this item — used for selection comparison. */
  value: T;
  /** Label shown in the toggle button. */
  label: string;
  /** When true, this item is disabled regardless of group disabled state. */
  disabled?: boolean;
}

export interface BTToggleGroupProps<T = string> {
  /** List of toggle options to render. */
  items: BTToggleGroupItem<T>[];
  /** Selection mode. 'single': at most one active. 'multiple': any number. Default: 'single'. */
  type?: 'single' | 'multiple';
  /**
   * Controlled selection value.
   * - single mode: T | null
   * - multiple mode: T[]
   */
  value?: T | T[] | null;
  /** Visual style forwarded to all child toggles. Default: 'default'. */
  variant?: BTToggleVariant;
  /** Size forwarded to all child toggles. Default: 'default'. */
  size?: BTToggleSize;
  /** When true, the entire group is non-interactive. Default: false. */
  disabled?: boolean;
  /** Fired when selection changes. */
  onChange?: (value: T | T[] | null) => void;
  /** Extra class name. */
  className?: string;
}
